import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Interview.css';

function Interview() {
  const navigate = useNavigate();
  const [step, setStep] = useState('upload'); // upload, interview, results
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [resumeData, setResumeData] = useState(null);
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [currentAnswer, setCurrentAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Prevent tab switching during interview
  useEffect(() => {
    if (step === 'interview') {
      // Warn before leaving page
      const handleBeforeUnload = (e) => {
        e.preventDefault();
        e.returnValue = 'Interview in progress. Are you sure you want to leave?';
        return e.returnValue;
      };

      // Prevent browser back button
      const handlePopState = (e) => {
        if (window.confirm('Interview in progress. Are you sure you want to leave?')) {
          return true;
        } else {
          window.history.pushState(null, '', window.location.pathname);
          e.preventDefault();
          return false;
        }
      };

      // Add event listeners
      window.addEventListener('beforeunload', handleBeforeUnload);
      window.history.pushState(null, '', window.location.pathname);
      window.addEventListener('popstate', handlePopState);

      // Cleanup
      return () => {
        window.removeEventListener('beforeunload', handleBeforeUnload);
        window.removeEventListener('popstate', handlePopState);
      };
    }
  }, [step]);

  // Detect tab visibility change
  useEffect(() => {
    if (step === 'interview') {
      const handleVisibilityChange = () => {
        if (document.hidden) {
          alert('⚠️ Please stay on this tab during the interview!');
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);

      return () => {
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }
  }, [step]);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile && selectedFile.type === 'application/pdf') {
      setFile(selectedFile);
    } else {
      alert('Please select a PDF file');
    }
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    setError('');
    const formData = new FormData();
    formData.append('resume', file);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/resume/upload', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      const data = await response.json();

      if (data.success) {
        setResumeData(data.resume);
        // Start interview session
        await startInterview(data.resume.id);
      } else {
        setError(data.message || 'Upload failed');
      }
    } catch (error) {
      setError('Network error. Please try again.');
    } finally {
      setUploading(false);
    }
  };

  const startInterview = async (resumeId) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:5000/api/interview/start', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ resumeId })
      });

      const data = await response.json();

      if (data.success) {
        setSessionId(data.session.id);
        setMessages([{
          type: 'ai',
          text: data.session.question
        }]);
        setStep('interview');
      } else {
        setError(data.message || 'Failed to start interview');
      }
    } catch (error) {
      setError('Failed to start interview. Please try again.');
    }
  };

  const handleSendAnswer = async () => {
    if (!currentAnswer.trim() || loading) return;

    const userMessage = currentAnswer.trim();
    setCurrentAnswer('');
    setLoading(true);
    setError('');

    // Add user message to chat
    setMessages(prev => [...prev, {
      type: 'user',
      text: userMessage
    }]);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/answer`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ answer: userMessage })
      });

      const data = await response.json();

      if (data.success) {
        // Add AI response
        setMessages(prev => [...prev, {
          type: 'ai',
          text: data.question
        }]);
      } else {
        setError(data.message || 'Failed to get next question');
      }
    } catch (error) {
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCompleteInterview = async () => {
    if (!sessionId) return;

    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/complete`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      const data = await response.json();

      if (data.success) {
        // Redirect to dashboard to see results
        navigate('/dashboard');
      } else {
        setError(data.message || 'Failed to complete interview');
      }
    } catch (error) {
      setError('Failed to complete interview. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="interview-page">
      <div className="container-small">
        {error && <div className="alert alert-error">{error}</div>}

        {step === 'upload' && (
          <div className="upload-section fade-in">
            <h1>Upload Your Resume</h1>
            <p className="subtitle">Upload your resume to get personalized interview questions</p>

            <div className="upload-card">
              <div className="upload-icon">📄</div>
              <h3>Drag and drop your resume here</h3>
              <p>or click to browse (PDF only, max 3 pages)</p>

              <input
                type="file"
                accept=".pdf"
                onChange={handleFileChange}
                className="file-input"
                id="resume-upload"
              />
              <label htmlFor="resume-upload" className="btn btn-secondary">
                Choose File
              </label>

              {file && (
                <div className="file-selected">
                  <p>✓ {file.name}</p>
                  <button 
                    onClick={handleUpload} 
                    className="btn btn-primary"
                    disabled={uploading}
                  >
                    {uploading ? 'Processing...' : 'Start Interview'}
                  </button>
                </div>
              )}
            </div>

            <div className="upload-info">
              <h4>Requirements:</h4>
              <ul>
                <li>PDF format only</li>
                <li>Maximum 3 pages</li>
                <li>Clear, readable text</li>
                <li>Valid resume content</li>
              </ul>
            </div>
          </div>
        )}

        {step === 'interview' && (
          <div className="interview-section fade-in">
            <div className="interview-header">
              <h1>Interview in Progress</h1>
              <button 
                onClick={handleCompleteInterview} 
                className="btn btn-secondary"
                disabled={loading || messages.length < 4}
              >
                Complete Interview
              </button>
            </div>
            <p className="subtitle">Answer the questions to the best of your ability</p>

            <div className="chat-container">
              {messages.map((msg, index) => (
                <div key={index} className={`message ${msg.type}-message`}>
                  <div className="message-avatar">
                    {msg.type === 'ai' ? '🤖' : '👤'}
                  </div>
                  <div className="message-content">
                    <p>{msg.text}</p>
                  </div>
                </div>
              ))}

              {loading && (
                <div className="message ai-message">
                  <div className="message-avatar">🤖</div>
                  <div className="message-content">
                    <p className="typing">Thinking...</p>
                  </div>
                </div>
              )}

              <div className="message-input-container">
                <textarea
                  className="message-input"
                  placeholder="Type your answer here..."
                  rows="4"
                  value={currentAnswer}
                  onChange={(e) => setCurrentAnswer(e.target.value)}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendAnswer();
                    }
                  }}
                  disabled={loading}
                ></textarea>
                <button 
                  className="btn btn-primary" 
                  onClick={handleSendAnswer}
                  disabled={loading || !currentAnswer.trim()}
                >
                  {loading ? 'Sending...' : 'Send Answer'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Interview;
